// 三载体一致:纯 JS 数值(内联 mathjs+numericjs),零 DOM/CSS/uplink/shadow 足迹;default 导出
import AHP from 'https://cdn.jsdelivr.net/npm/ahp@2/+esm';
const ahp = new AHP();
ahp.import({ items: data.items, criteria: data.criteria, criteriaItemRank: data.criteriaItemRank, criteriaRank: data.criteriaRank });
const out = ahp.run(); // { rankedScoreMap, rankedScores, criteriaRankMetaMap:{weightedVector,cr}, itemRankMetaMap:{…:{cr}}, error }
if (out.error) throw out.error;
